#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 11 (Layer 5): cierre del camino critico.
#
# PROBLEMA (sintesis OOC): WNS = -1.924 ns, 11 caminos violados a 100 MHz.
#   8 peores (-1.924 a -1.763): u_s2/fc_i_reg -> u_s2/lg_ram_reg
#       40 niveles logicos, 11.457 ns. El estado S_FC encadenaba en un ciclo:
#       contador -> LUTRAM(w3_ram) -> DSP -> acarreo de 32 bits -> lg_ram
#   3 restantes (-0.198 a -0.073): u_s2/rq_i_reg -> u_s2/c2_ram_reg
#       El estado S_C2_RQ leia accm, requantizaba y escribia en un ciclo.
#
# CORRECCION: segmentacion en etapas registradas.
#   S_FC     -> S_FC_RD (lectura) + S_FC_MAC (producto) + S_FC_RQ (requantize)
#   S_C2_RQ  -> S_C2_RQRD (lectura) + S_C2_RQ (requantize y escritura)
#
# COSTE: la FC pasa de 2560 a ~5120 ciclos, marginal frente a los ~14000 de
# conv2. Ninguna otra etapa cambia.
#
# CRITERIO: las firmas congeladas NO cambian.
#   pool2 0xA87E298C   logits 0xF7FF3389   clase 0x6084FD2A
#
# NO VERIFICADO POR CLAUDE: sin Vivado en el contenedor no se puede confirmar
# que el timing cierre. Hay que resintetizar en la workstation.
#
# Reemplaza rtl/npu_seq_full.vhd. Requiere Pasos 1-10.
# Linea esperada al final:
# NPU PASO11 OK TIMING FIRMAS INVARIANTES
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
for f in rtl/npu_top.vhd rtl/npu_array.vhd tb/tb_npu_seq_full.vhd; do
  if [ ! -f "$DIR/$f" ]; then
    echo "FALLO: falta $f (corre primero los Pasos 1-10)"; exit 1
  fi
done
mkdir -p "$DIR/rtl/prev_paso11"
cp "$DIR/rtl/npu_seq_full.vhd" "$DIR/rtl/prev_paso11/" 2>/dev/null || true
base64 -d << "EOF" > "$DIR/rtl/npu_seq_full.vhd"

EOF
base64 -d << "EOF" > "$DIR/run_timing.sh"

EOF
base64 -d << "EOF" > "$DIR/run_timing_mut.sh"

EOF
chmod +x "$DIR/run_timing.sh" "$DIR/run_timing_mut.sh"
cd "$DIR"
bash run_timing.sh
)
